async function addGrowspaceNote(growspaceId, payload) {
    await hassCall('growspace_manager/add_growspace_note', {
        growspace_id: growspaceId,
        notes: payload.notes,
        images: payload.images ?? [],
    }, AddNoteResponseSchema);
}
