/**
 * Keyboard Actions - Pure functions for keyboard navigation.
 * Encapsulates keyboard shortcuts and navigation logic without coupling to store lifecycle.
 */
/**
 * Get the currently visible plants for the selected device.
 * Excludes plants that are marked for optimistic deletion.
 */
function getVisiblePlants(ctx) {
    const selectedDevice = ctx.grid.$selectedDevice.get();
    if (!selectedDevice)
        return [];
    const devices = ctx.data.$devices.get();
    const device = devices.find((d) => d.deviceId === selectedDevice);
    if (!device)
        return [];
    return device.plants.filter((p) => !ctx.data.$optimisticDeletedPlantIds.get().has(p.attributes.plant_id || ''));
}
/**
 * Handle keyboard navigation for the growspace grid.
 * Supports arrow key navigation, enter/space for selection, and delete/backspace for removal.
 */
function handleKeyboardNavigation(ctx, key) {
    // Escape exits edit mode
    if (ctx.ui.$isEditMode.get() && key === 'Escape') {
        exitEditMode(ctx);
        return;
    }
    const plants = getVisiblePlants(ctx);
    if (plants.length === 0)
        return;
    const currentIndex = ctx.ui.$focusedPlantIndex.get();
    switch (key) {
        case 'ArrowRight':
            ctx.ui.setFocusedPlantIndex((currentIndex + 1) % plants.length);
            break;
        case 'ArrowLeft':
            ctx.ui.setFocusedPlantIndex((currentIndex - 1 + plants.length) % plants.length);
            break;
        case 'Enter':
        case ' ': {
            if (currentIndex >= 0 && currentIndex < plants.length) {
                const plantId = plants[currentIndex].attributes.plant_id;
                if (plantId) {
                    select(plantId);
                }
            }
            break;
        }
        case 'Delete':
        case 'Backspace':
            if (currentIndex >= 0 && currentIndex < plants.length) {
                const focusedPlant = plants[currentIndex];
                // logic in plant-actions implies we pass IDs.
                // In plantActions.handleDeletePlant, it expects string or string[].
                // But in original keyboard-actions it passed entity_id. Let's check plant type.
                // Looking at getVisiblePlants above, plants are PlantEntity.
                // PlantEntity has entity_id and attributes. attributes has plant_id.
                // The handleDeletePlant in plant-actions checks for plant_id or entity_id.
                // Let's pass the ID we can find.
                const idToDelete = focusedPlant.attributes.plant_id || focusedPlant.entity_id;
                handleDeletePlant(ctx, idToDelete);
            }
            else if (ctx.ui.$selectedPlants.get().size > 0) {
                // If multiple plants are selected, delete them
                handleDeletePlant(ctx, Array.from(ctx.ui.$selectedPlants.get()));
            }
            break;
    }
}

class ActionDispatcher {
    constructor(store) {
        this.store = store;
        this.plant = {
            update: (id, updates) => updatePlant(this.ctx, id, updates),
            delete: (id) => handleDeletePlant(this.ctx, id),
            move: (plant, growspace) => movePlantToGrowspace(this.ctx, plant, growspace),
            drop: (row, col, target, source) => handlePlantDrop(this.ctx, row, col, target, source),
            nextStage: (plant) => movePlantToNextStage(this.ctx, plant),
            harvest: (plant, metrics) => movePlantToNextStage(this.ctx, plant, metrics),
            takeClone: (mother, num, targetGrowspaceId) => takeClone(this.ctx, mother, num, targetGrowspaceId),
            updateFromDialog: (state) => updatePlantFromDialog(this.ctx, state),
            finishDrying: (plant) => movePlantToNextStage(this.ctx, plant),
            add: (gid, r, c, s, p) => confirmAddPlant(this.ctx, {
                row: r,
                col: c,
                strain: s,
                phenotype: p,
            }),
            addBatch: (detail) => confirmAddPlants(this.ctx, detail),
            saveHarvestMetrics: (plantId, metrics) => saveHarvestMetrics(this.ctx, plantId, metrics),
            scorePhenotype: (plantId, scores) => scorePhenotype(this.ctx, plantId, scores),
            printLabel: (params) => printLabel(this.ctx, params),
            logDryingWeight: (plantId, weightGrams, date) => logDryingWeight(this.ctx, plantId, weightGrams, date),
            logMoistureReading: (plantId, moisturePercent, date) => logMoistureReading(this.ctx, plantId, moisturePercent, date),
            setVisualTag: (plantId, visualTag) => setVisualTag(this.ctx, plantId, visualTag),
            confirmAdd: async (detail) => {
                if (!detail.strain)
                    return;
                await confirmAddPlant(this.ctx, detail);
            },
            batchAction: async (action, entityIds, data) => {
                if (entityIds.length === 0)
                    return;
                if (action === 'remove') {
                    entityIds.forEach((id) => this.ctx.data.addOptimisticDeletedPlantId(id));
                }
                try {
                    await this.ctx.dataService.callService('growspace_manager', 'batch_action', {
                        entity_ids: entityIds,
                        action,
                        data: data || {},
                    });
                    this.ctx.ui.showToast(`Batch ${action} completed for ${entityIds.length} plant(s)`, 'success');
                    this.ctx.ui.clearPlantSelection();
                    this.ctx.ui.setEditMode(false);
                    await this.ctx.refreshData();
                }
                catch (err) {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    console.error(`Batch ${action} failed:`, err);
                    this.ctx.ui.showToast(`Batch ${action} failed: ${error}`, 'error');
                    if (action === 'remove') {
                        entityIds.forEach((id) => this.ctx.data.removeOptimisticDeletedPlantId(id));
                    }
                }
            },
        };
        this.growspace = {
            add: (detail) => addGrowspace(this.ctx, detail.name, detail.rows, detail.plantsPerRow, detail.notificationService),
            update: (detail) => updateGrowspace(this.ctx, detail.growspaceId, detail.name, detail.rows, detail.plantsPerRow),
            remove: (id) => removeGrowspace(this.ctx, id),
            removeEnvironment: (id) => this.ctx.dataService.removeEnvironment(id),
            resetWaterTracking: (id) => this.ctx.dataService.resetWaterTracking(id),
        };
        this.strain = {
            add: (data) => addStrain(this.ctx, data),
            update: (data) => updateStrain(this.ctx, data),
            remove: (key) => removeStrain(this.ctx, key),
        };
        this.history = {
            undo: () => this.store.undo(),
            redo: () => this.store.redo(),
            canUndo: () => this.store.canUndo,
            canRedo: () => this.store.canRedo,
        };
        this.ui = {
            /** Toggle plant selection state */
            togglePlantSelection: (plantOrId) => togglePlantSelection(this.ctx, plantOrId),
            /** Open add plant dialog at specific position */
            openAddPlantDialog: (row, col) => openAddPlantDialog(this.ctx, row, col),
            /** Open plant overview dialog */
            openPlantOverviewDialog: (plant, selectedIds) => openPlantOverviewDialog(this.ctx, plant, selectedIds),
            /** Select all plants in current growspace */
            selectAllPlants: () => selectAllPlants(this.ctx),
            /** Open strain recommendation dialog */
            openStrainRecommendationDialog: () => openStrainRecommendationDialog(this.ctx),
            /** Export strain library as JSON */
            exportStrainLibrary: () => exportStrainLibrary(this.ctx),
            setIsCompactView: (value) => setIsCompactView(this.ctx, value),
            toggleHeaderExpansion: () => toggleHeaderExpansion(this.ctx),
            showToast: (message, type = 'info') => showToast(this.ctx, message, type),
            /** Refresh all data */
            refreshData: () => this.store.refreshData(),
            /** Set the active dialog */
            setActiveDialog: (dialog) => setActiveDialog(this.ctx, dialog),
            /** Close the current dialog */
            closeDialog: () => closeDialog(this.ctx),
            toast: (message, type = 'info') => showToast(this.ctx, message, type),
            openNutrientPresetsDialog: () => openNutrientPresetsDialog(this.ctx),
            openIPMDialog: (context) => openIPMDialog(this.ctx, context),
            openLogbookDialog: () => openLogbookDialog(this.ctx),
            openConfigDialog: (device) => openConfigDialog(this.ctx, device),
            openStrainLibraryDialog: () => openStrainLibraryDialog(this.ctx),
            openIrrigationDialog: (options) => openIrrigationDialog(this.ctx, options),
            openGrowMasterDialog: (growspaceId) => openGrowMasterDialog(this.ctx, growspaceId),
            openWateringDialog: (options) => openWateringDialog(this.ctx, options),
            openTrainingDialog: (plantIds, growspaceId) => openTrainingDialog(this.ctx, plantIds, growspaceId),
            openNutrientsDialog: () => openNutrientsDialog(this.ctx),
            openSnapshotsDialog: (growspaceId) => openSnapshotsDialog(this.ctx, growspaceId),
            openCropSteeringDialog: (growspaceId) => openCropSteeringDialog(this.ctx, growspaceId),
            openECRampDialog: (growspaceId) => openECRampDialog(this.ctx, growspaceId),
            openGrowReportDialog: (growspaceId) => openGrowReportDialog(this.ctx, growspaceId),
            openBatchWateringDialog: (growspaceId) => openBatchWateringDialog(this.ctx, growspaceId),
            openBatchTrainingDialog: (growspaceId) => openBatchTrainingDialog(this.ctx, growspaceId),
            openBatchCloneDialog: () => openBatchCloneDialog(this.ctx),
            openBatchPrintLabelsDialog: () => openBatchPrintLabelsDialog(this.ctx),
            clearPlantSelection: () => clearPlantSelection(this.ctx),
            exitEditMode: () => exitEditMode(this.ctx),
            handleDeepLink: (plantId) => handleDeepLink(this.ctx, plantId),
            handleKeyboardNavigation: (key) => handleKeyboardNavigation(this.ctx, key),
            deleteSelectedPlants: async () => {
                const ids = Array.from(this.ctx.ui.$selectedPlants.get());
                if (!ids.length)
                    return;
                await handleDeletePlant(this.ctx, ids);
            },
            toggleEnvGraph: (metric) => {
                if (metric === 'crop_steering') {
                    const gsId = this.ctx.grid.$selectedDevice.get();
                    if (gsId)
                        openCropSteeringDialog(this.ctx, gsId);
                    return;
                }
                if (!this.store.history)
                    return;
                const isNowActive = this.store.history.toggleEnvGraph(metric);
                if (isNowActive && this.ctx.ui.$viewMode.get() === ViewMode.HEADER) {
                    this.ctx.ui.setViewMode(ViewMode.STANDARD);
                }
            },
        };
        this.library = {
            fetchStrains: (force = false) => fetchStrainLibrary(this.ctx, force),
            fetchNutrientPresets: (force = false) => fetchNutrientPresets(this.ctx, force),
            fetchIPMPresets: (force = false) => fetchIPMPresets(this.ctx, force),
            fetchNutrientInventory: (force = false) => fetchNutrientInventory(this.ctx, force),
            updateNutrientStock: (id, name, currentMl, initialMl) => updateNutrientStock(this.ctx, id, name, currentMl, initialMl),
            removeNutrientStock: (id) => removeNutrientStock(this.ctx, id),
            fetchECRampCurves: (force = false) => fetchECRampCurves(this.ctx, force),
            saveECRampCurve: (data) => saveECRampCurve(this.ctx, data),
            removeECRampCurve: (id) => removeECRampCurve(this.ctx, id),
            import: async (file, _replace) => {
                try {
                    const content = await file.text();
                    const strains = JSON.parse(content);
                    if (!Array.isArray(strains))
                        throw new Error('Invalid format');
                    for (const strain of strains) {
                        await addStrain(this.ctx, strain);
                    }
                    this.ctx.ui.showToast('Library imported successfully', 'success');
                    await fetchStrainLibrary(this.ctx, true);
                }
                catch (e) {
                    const error = e instanceof Error ? e.message : 'Unknown error';
                    console.error('Import failed', e);
                    this.ctx.ui.showToast('Import failed: ' + error, 'error');
                }
            },
        };
        this.nutrient = {
            savePreset: (preset) => saveNutrientPreset(this.ctx, preset),
            removePreset: (id) => removeNutrientPreset(this.ctx, id),
        };
        this.snapshots = {
            list: (growspaceId) => getSnapshots(this.ctx, growspaceId),
            capture: (growspaceId) => captureSnapshot(this.ctx, growspaceId),
            visionHistory: (growspaceId) => getVisionHistory(this.ctx, growspaceId),
            triggerCheckup: (growspaceId) => triggerVisionCheckup(this.ctx, growspaceId),
            updateCheckupConfig: (growspaceId, config) => updateVisionCheckupConfig(this.ctx, growspaceId, config),
        };
        this.report = {
            fetch: (growspaceId) => fetchGrowReport(this.ctx, growspaceId),
            export: (growspaceId, format) => exportGrowReport(this.ctx, growspaceId, format),
        };
        this.ai = {
            /** Analyze all growspaces at once */
            analyzeAll: () => analyzeGrowspace(this.ctx, '', true),
            /** Ask for advice about the currently selected device */
            askAdvice: (query) => analyzeGrowspace(this.ctx, query, false),
            /** Get a strain recommendation */
            strainRecommendation: (query) => getStrainRecommendation(this.ctx, query),
        };
        this.environment = {
            configure: (data) => configureEnvironment(this.ctx, data),
            remove: (growspaceId) => removeEnvironment(this.ctx, growspaceId),
            resetWaterTracking: (growspaceId) => resetWaterTracking(this.ctx, growspaceId),
            waterPlant: (plantId, amount, nutrients, presetId) => waterPlant(this.ctx, plantId, amount, nutrients, presetId),
            waterGrowspace: (growspaceId, amount, nutrients, presetId) => waterGrowspace(this.ctx, growspaceId, amount, nutrients, presetId),
        };
        this.breeder = {
            update: (oldName, newName, logo) => updateBreeder(this.ctx, oldName, newName, logo),
            delete: (name) => deleteBreeder(this.ctx, name),
        };
        this.genetics = {
            addSeedBatch: (data) => addSeedBatch(this.ctx, data),
            updateSeedBatch: (data) => updateSeedBatch(this.ctx, data),
            logPollination: (data) => logPollination(this.ctx, data),
            updatePollination: (data) => updatePollination(this.ctx, data),
            deletePollination: (eventId) => deletePollination(this.ctx, eventId),
            fetchData: () => fetchGeneticsData(this.ctx),
            harvestSeeds: (data) => harvestSeeds(this.ctx, data),
            deleteSeedBatch: (batchId) => deleteSeedBatch(this.ctx, batchId),
            setPlantSex: (plantId, sex) => setPlantSex(this.ctx, plantId, sex),
            sowSeed: (batchId, plantId) => sowSeed(this.ctx, batchId, plantId),
            getLineageTree: (plantId) => getLineageTree(this.ctx, plantId),
            getStrainLineageTree: (strainName) => getStrainLineageTree(this.ctx, strainName),
            updateStrainLineageTree: (strainName, parents) => updateStrainLineageTree(this.ctx, strainName, parents),
        };
        this.ipm = {
            apply: (detail) => applyIPM(this.ctx, detail),
            savePreset: (preset) => saveIPMPreset(this.ctx, preset),
            removePreset: (presetId) => removeIPMPreset(this.ctx, presetId),
        };
    }
    get ctx() {
        return this.store.context;
    }
}

/**
 * DeviceState slice — the single place in the codebase that reads hass.states
 * for device-controlled entities and exposes normalized DeviceSnapshot atoms.
 *
 * Public API (atoms):
 *   deviceSnapshots$        — read: Map<growspaceId, DeviceSnapshot> (one entry per growspace)
 *
 * Public API (bootstrap writes):
 *   setDeviceSnapshot()     — compute + store snapshot for a growspace (called by SyncService
 *                             on every hass update)
 *
 * Public API (pure computation):
 *   computeDeviceSnapshot() — derive a DeviceSnapshot from a device + hass states snapshot.
 *                             Exported so HeaderMetrics and tests can call it directly.
 */
// ---------------------------------------------------------------------------
// Internal constants
// ---------------------------------------------------------------------------
const UNAVAILABLE_STATES = new Set(['unavailable', 'unknown']);
// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------
/**
 * Normalize a light sensor entity state.
 * - If `unit_of_measurement` is `%`: return a rounded percentage string.
 * - Otherwise: return "On" / "Off" for binary states.
 */
function _normalizeLightSensor(entity) {
    if (!entity)
        return undefined;
    if (UNAVAILABLE_STATES.has(entity.state))
        return undefined;
    const unit = entity.attributes?.unit_of_measurement;
    if (unit === '%') {
        const n = parseFloat(entity.state);
        return isNaN(n) ? undefined : `${Math.round(n)}%`;
    }
    if (entity.state === 'on')
        return 'On';
    if (entity.state === 'off')
        return 'Off';
    return undefined;
}
/** Normalize an on/off device entity state to "On", "Off", or undefined. */
function _normalizeOnOff(entity) {
    if (!entity)
        return undefined;
    if (UNAVAILABLE_STATES.has(entity.state))
        return undefined;
    if (entity.state === 'on')
        return 'On';
    if (entity.state === 'off')
        return 'Off';
    return undefined;
}
/**
 * Build a DeviceEntry for a list of entity IDs using the given normalizer.
 * Returns null when the entity list is empty (device category not configured).
 */
function _buildEntry(entityIds, hassStates, icon, normalizer) {
    if (entityIds.length === 0)
        return null;
    if (entityIds.length === 1) {
        const value = normalizer(hassStates[entityIds[0]]);
        return { entityIds, value, icon };
    }
    // Multiple entities: collect individual values; surface "Multiple" as the aggregate.
    const multiValues = entityIds
        .map((id) => normalizer(hassStates[id]))
        .filter((v) => v !== undefined);
    return {
        entityIds,
        value: 'Multiple',
        multiValues: multiValues.length > 0 ? multiValues : undefined,
        icon,
    };
}
// ---------------------------------------------------------------------------
// Pure computation (exported — used by HeaderMetrics and tests)
// ---------------------------------------------------------------------------
/**
 * Derive a normalized DeviceSnapshot for a growspace from the current hass states.
 *
 * This is the canonical place to read device-controlled entity states from hass.states.
 * All downstream consumers (HeaderMetrics, cards) should subscribe to the atom
 * instead of calling this directly.
 */
function computeDeviceSnapshot(device, hassStates) {
    const env = device.environmentAttributes ?? {};
    const lightIds = env.lightSensors ?? (env.lightSensor ? [env.lightSensor] : []);
    const exhaustIds = env.exhaustFanEntities ?? (env.exhaustEntity ? [env.exhaustEntity] : []);
    const circulationIds = env.circulationFanEntities ?? (env.circulationFanEntity ? [env.circulationFanEntity] : []);
    const humidifierIds = env.humidifierEntities ?? (env.humidifierEntity ? [env.humidifierEntity] : []);
    const dehumidifierIds = env.dehumidifierEntities ?? (env.dehumidifierEntity ? [env.dehumidifierEntity] : []);
    return {
        lightSensors: _buildEntry(lightIds, hassStates, mdiLightbulbOn, _normalizeLightSensor),
        exhaustFans: _buildEntry(exhaustIds, hassStates, mdiFan, _normalizeOnOff),
        circulationFans: _buildEntry(circulationIds, hassStates, mdiFan, _normalizeOnOff),
        humidifiers: _buildEntry(humidifierIds, hassStates, mdiAirHumidifier, _normalizeOnOff),
        dehumidifiers: _buildEntry(dehumidifierIds, hassStates, mdiAirHumidifierOff, _normalizeOnOff),
    };
}
// ---------------------------------------------------------------------------
// Atoms (public)
// ---------------------------------------------------------------------------
/** Per-growspace device state snapshots — keyed by growspaceId. */
const deviceSnapshots$ = atom(new Map());
// ---------------------------------------------------------------------------
// Bootstrap write (public)
// ---------------------------------------------------------------------------
/**
 * Compute and store the DeviceSnapshot for a growspace.
 * Called by SyncService after each hass update.
 */
function setDeviceSnapshot(growspaceId, device, hassStates) {
    const snapshot = computeDeviceSnapshot(device, hassStates);
    const updated = new Map(deviceSnapshots$.get());
    updated.set(growspaceId, snapshot);
    deviceSnapshots$.set(updated);
}

/**
 * Service responsible for synchronizing data between Home Assistant and the local store.
 * Handles caching, optimizing updates, and managing the initial data fetch.
 */
class SyncService {
    setCardConfig(config) {
        if (config.default_growspace !== this._cardConfig?.default_growspace) {
            this.uiStore.setDefaultApplied(false);
        }
        this._cardConfig = config;
    }
    constructor(dataService, dataStore, uiStore) {
        this.dataService = dataService;
        this.dataStore = dataStore;
        this.uiStore = uiStore;
        this._isFetchingWS = false;
        this._watchedEntities = new Set();
        /** Per-card config — not shared across card instances. */
        this._cardConfig = {};
    }
    /**
     * Updates the Home Assistant reference and triggers data refresh if necessary.
     * Implements optimization to avoid unnecessary processing.
     */
    updateHass(hass) {
        // Optimization: Referencing check
        if (this._lastHassRef === hass)
            return;
        this.dataService.updateHass(hass);
        // If cache empty, fetch initial
        const currentCache = this.dataStore.$wsDataCache.get();
        if (Object.keys(currentCache).length === 0 && !this._isFetchingWS) {
            this.refreshGrowspaceData();
            this._lastHassRef = hass;
            return;
        }
        // Deep Optimization: Only update if watched entities changed
        if (this._watchedEntities.size > 0 && this._lastHassRef) {
            let hasChanged = false;
            for (const entityId of this._watchedEntities) {
                const newState = hass.states[entityId];
                const oldState = this._lastHassRef.states[entityId];
                // Fast reference check + check for missing/new states
                if (newState !== oldState ||
                    (newState === undefined && oldState !== undefined) ||
                    (newState !== undefined && oldState === undefined)) {
                    hasChanged = true;
                    break;
                }
            }
            if (!hasChanged) {
                this._lastHassRef = hass;
                return;
            }
        }
        // Just re-calculate derived state (sync) because entities might have changed
        this.updateDevicesState();
        this.uiStore.setIsLoading(false);
        this._lastHassRef = hass;
    }
    /**
     * Refreshes growspace data from the WebSocket API.
     * Manages loading state and error handling.
     */
    async refreshGrowspaceData() {
        if (!this.dataService.hass || this._isFetchingWS)
            return;
        this._isFetchingWS = true;
        // Show loading spinner if we have no devices yet
        if (this.dataStore.$devices.get().length === 0) {
            this.uiStore.setIsLoading(true);
        }
        try {
            const data = await this.dataService.fetchGrowspaceData();
            this.dataStore.setWsDataCache(data || {});
            this.updateDevicesState();
        }
        catch (e) {
            console.error('Failed to fetch growspace data', e);
        }
        finally {
            this._isFetchingWS = false;
            this.uiStore.setIsLoading(false);
        }
    }
    /**
     * Updates the devices state in the store based on cached data and current HA state.
     * Also updates the list of watched entities for optimization.
     */
    updateDevicesState() {
        const devices = this.dataService.getGrowspaceDevices(this.dataStore.$wsDataCache.get());
        const currentDevices = this.dataStore.$devices.get();
        if (!this._areDeviceArraysEqual(currentDevices, devices)) {
            this.dataStore.setDevices(devices);
            setDevices(devices);
        }
        // Update device-controlled entity snapshots and populate watched entities for next update cycle
        const hassStates = this.dataService.hass?.states ?? {};
        this._watchedEntities.clear();
        devices.forEach((d) => {
            // Device state snapshot (lights, fans, humidifiers, dehumidifiers)
            setDeviceSnapshot(d.deviceId, d, hassStates);
            // Plants
            (d.plants || []).forEach((p) => {
                const eid = p.entity_id;
                if (eid)
                    this._watchedEntities.add(eid);
            });
            // Irrigation Config
            if (d.irrigationConfig?.irrigationPumpEntity)
                this._watchedEntities.add(d.irrigationConfig.irrigationPumpEntity);
            if (d.irrigationConfig?.drainPumpEntity)
                this._watchedEntities.add(d.irrigationConfig.drainPumpEntity);
            // Environment Sensors (e.g. temperature_sensor: 'sensor.x')
            if (d.environmentAttributes) {
                Object.values(d.environmentAttributes).forEach((val) => {
                    if (typeof val === 'string' && val.includes('.')) {
                        this._watchedEntities.add(val);
                    }
                });
            }
        });
        const selectedDevice = selectedDeviceId$.get();
        // Auto-select if needed
        if ((!selectedDevice || !this.uiStore.$defaultApplied.get()) && devices.length > 0) {
            const config = this._cardConfig;
            if (this.uiStore.$defaultApplied.get())
                return;
            const defaultDevice = devices.find((d) => d.deviceId === config.default_growspace || d.name === config.default_growspace);
            if (defaultDevice) {
                setSelectedDeviceId(defaultDevice.deviceId);
                this.uiStore.setDefaultApplied(true);
                return;
            }
            // Fallback to first device
            setSelectedDeviceId(devices[0].deviceId);
            this.uiStore.setDefaultApplied(true);
        }
    }
    _areDeviceArraysEqual(a, b) {
        if (a === b)
            return true;
        if (!a || !b)
            return false;
        if (a.length !== b.length)
            return false;
        if (a.length === 0)
            return true;
        try {
            return JSON.stringify(a) === JSON.stringify(b);
        }
        catch (_) {
            return false;
        }
    }
}

class UndoRedoManager {
    constructor(showToast) {
        this.showToast = showToast;
        this._undoStack = [];
        this._redoStack = [];
        this.MAX_UNDO_ACTIONS = 3;
    }
    pushAction(action) {
        this._undoStack.push(action);
        if (this._undoStack.length > this.MAX_UNDO_ACTIONS) {
            this._undoStack.shift(); // Remove oldest
        }
        this._redoStack = []; // Clear redo on new action
        // Show toast with Undo button
        this.showToast(action.description, 'success', {
            label: 'Undo',
            callback: () => this.undo(),
        });
    }
    get canUndo() {
        return this._undoStack.length > 0;
    }
    get canRedo() {
        return this._redoStack.length > 0;
    }
    async undo() {
        const action = this._undoStack.pop();
        if (!action)
            return;
        try {
            await action.reverse();
            this._redoStack.push(action);
            this.showToast(`Undone: ${action.description}`, 'info');
        }
        catch (err) {
            console.error('[Undo failed]', err);
            this.showToast('Undo failed', 'error');
        }
    }
    async redo() {
        const action = this._redoStack.pop();
        if (!action)
            return;
        try {
            await action.redo();
            this._undoStack.push(action);
            this.showToast(`Redone: ${action.description}`, 'info');
        }
        catch (err) {
            console.error('[Redo failed]', err);
            this.showToast('Redo failed', 'error');
        }
    }
}

class OptimisticManager {
    constructor(data, undoRedoManager) {
        this.data = data;
        this.undoRedoManager = undoRedoManager;
        this._pendingActions = new Map();
    }
    /**
     * Apply an optimistic update immediately.
     * Returns the action ID to be used for confirmation or rollback.
     */
    async applyOptimisticUpdate(type, payload, applyFn, revertFn) {
        const id = typeof crypto !== 'undefined' && crypto.randomUUID
            ? crypto.randomUUID()
            : Math.random().toString(36).substring(2) + Date.now().toString(36);
        // 1. Store the action for potential rollback
        this._pendingActions.set(id, {
            id,
            type,
            payload,
            revert: revertFn,
            timestamp: Date.now(),
        });
        // 2. Execute the optimistic change immediately
        try {
            await applyFn(payload);
        }
        catch (e) {
            console.error('Failed to apply optimistic update', e); // Assuming _LOGGER is console.error
            this.rollbackUpdate(id);
            throw e; // Rethrow so caller knows it failed
        }
        return id;
    }
    /**
     * Mark an optimistic action as successfully committed to the backend.
     * If `addToHistory` is true, we push a "reverse" action to the UndoRedoManager.
     */
    confirmUpdate(actionId, historyOptions) {
        const action = this._pendingActions.get(actionId);
        if (!action)
            return; // Already cleared or handled
        if (historyOptions) {
            // Transform the Revert function into an Undo action
            this.undoRedoManager.pushAction({
                type: action.type,
                description: historyOptions.description,
                reverse: async () => {
                    // When user clicks Undo, we execute the revert logic
                    // Note: Revert logic usually re-applies the old state to API
                    await action.revert();
                },
                redo: historyOptions.redo,
            });
        }
        this._pendingActions.delete(actionId);
    }
    /**
     * Rollback an optimistic action because the backend call failed.
     */
    async rollbackUpdate(actionId) {
        const action = this._pendingActions.get(actionId);
        if (!action)
            return;
        console.warn(`Rolling back optimistic action: ${action.type}`, action.payload);
        try {
            await action.revert();
        }
        catch (e) {
            console.error('Critical: Failed to rollback optimistic update', e);
            // Force a full refresh as a fallback if rollback fails
            // this.dataStore.requestRefetch(); // detailed implementation depends on store
        }
        finally {
            this._pendingActions.delete(actionId);
        }
    }
    /**
     * Check if there are pending actions for a specific entity ID (if payload has IDs)
     * Helpful for UI loading states or disabling interactions
     */
    isEntityPending(entityId) {
        for (const action of this._pendingActions.values()) {
            const p = action.payload;
            // Naive check for common ID fields
            if (p?.plantId === entityId || p?.plant_id === entityId || p?.entity_id === entityId) {
                return true;
            }
            if (Array.isArray(p?.plantIds) && p.plantIds.includes(entityId)) {
                return true;
            }
        }
        return false;
    }
}

/**
 * Event Bus - Centralized event system for cross-component communication
 *
 * Provides a typed, subscription-based event system that allows components
 * to communicate without tight coupling or prop drilling.
 */
/**
 * Event Bus for pub/sub communication
 */
class EventBus {
    constructor() {
        this.handlers = new Map();
        this.debug = false;
    }
    /**
     * Enable/disable debug logging
     */
    setDebug(enabled) {
        this.debug = enabled;
    }
    /**
     * Subscribe to an event
     *
     * @param event - Event name to subscribe to
     * @param handler - Handler function to call when event is emitted
     * @returns Unsubscribe function
     */
    on(event, handler) {
        if (!this.handlers.has(event)) {
            this.handlers.set(event, new Set());
        }
        const handlers = this.handlers.get(event);
        handlers.add(handler);
        if (this.debug) {
            console.log(`[EventBus] Subscribed to "${event}" (${handlers.size} handlers)`);
        }
        // Return unsubscribe function
        return () => {
            handlers.delete(handler);
            if (handlers.size === 0) {
                this.handlers.delete(event);
            }
            if (this.debug) {
                console.log(`[EventBus] Unsubscribed from "${event}"`);
            }
        };
    }
    /**
     * Emit an event to all subscribers
     *
     * @param event - Event name to emit
     * @param payload - Data to pass to handlers
     */
    emit(event, payload) {
        const handlers = this.handlers.get(event);
        if (!handlers || handlers.size === 0) {
            if (this.debug) {
                console.warn(`[EventBus] No handlers for event "${event}"`);
            }
            return;
        }
        if (this.debug) {
            console.log(`[EventBus] Emitting "${event}" to ${handlers.size} handlers`, payload);
        }
        // Call all handlers (catch errors to prevent one handler from breaking others)
        handlers.forEach((handler) => {
            try {
                handler(payload);
            }
            catch (error) {
                console.error(`[EventBus] Handler error for event "${event}":`, error);
            }
        });
    }
    /**
     * Subscribe to an event, but only handle it once
     *
     * @param event - Event name to subscribe to
     * @param handler - Handler function (will be called once and auto-unsubscribed)
     */
    once(event, handler) {
        const wrappedHandler = (payload) => {
            handler(payload);
            this.handlers.get(event)?.delete(wrappedHandler);
            if (this.debug) {
                console.log(`[EventBus] One-time handler for "${event}" executed and removed`);
            }
        };
        this.on(event, wrappedHandler);
    }
    /**
     * Check if event has any subscribers
     *
     * @param event - Event name to check
     * @returns True if event has subscribers
     */
    hasSubscribers(event) {
        const handlers = this.handlers.get(event);
        return !!handlers && handlers.size > 0;
    }
    /**
     * Get number of subscribers for an event
     *
     * @param event - Event name to check
     * @returns Number of subscribers
     */
    subscriberCount(event) {
        return this.handlers.get(event)?.size || 0;
    }
    /**
     * Remove all subscribers for a specific event
     *
     * @param event - Event name to clear
     */
    off(event) {
        this.handlers.delete(event);
        if (this.debug) {
            console.log(`[EventBus] Cleared all handlers for "${event}"`);
        }
    }
    /**
     * Remove all subscribers for all events
     */
    clear() {
        const eventCount = this.handlers.size;
        this.handlers.clear();
        if (this.debug) {
            console.log(`[EventBus] Cleared all handlers (${eventCount} events)`);
        }
    }
    /**
     * Get all event names that have subscribers
     *
     * @returns Array of event names
     */
    getEvents() {
        return Array.from(this.handlers.keys());
    }
}

